#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char S[100005]; scanf("%s", S);
        int ans = 0;
        for (int i = 0; i < N-1; ++i) {
            if (S[i] == S[i+1]) ans++;
        }
        printf("%d\n", ans);
    }
    return 0;
}

